#include <stdio.h>
#include <stdlib.h>
#define MAXV 1000000
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    // sieve
    char *isComp = calloc(MAXV+1, sizeof(char));
    int *primes = malloc((MAXV/10)*sizeof(int)); // enough space
    int pcnt = 0;
    for(int i=2;i<=MAXV;i++) if(!isComp[i]){
        primes[pcnt++] = i;
        if((long long)i*i<=MAXV) for(int j=i*i;j<=MAXV;j+=i) isComp[j]=1;
    }
    while(T--){
        int N; scanf("%d",&N);
        int idx=0;
        if(N%2==1){
            printf("1");
            idx=1;
        }
        int need = N/2; // number of primes needed
        for(int i=0;i<need;i++){
            if(idx) printf(" ");
            printf("%d %d",primes[i],primes[i]);
            idx=1;
        }
        printf("\n");
    }
    free(isComp); free(primes);
    return 0;
}

