import java.io.*;
import java.util.*;
public class Main {
    static final int MAXV = 1_000_000;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        // sieve
        boolean[] comp = new boolean[MAXV + 1];
        List<Integer> primes = new ArrayList<>();
        for (int i = 2; i <= MAXV; i++) if (!comp[i]) {
            primes.add(i);
            if ((long) i * i <= MAXV) {
                for (int j = i * i; j <= MAXV; j += i) comp[j] = true;
            }
        }
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            boolean first = true;
            if (N % 2 == 1) {
                out.append(1);
                first = false;
            }
            int need = N / 2;
            for (int i = 0; i < need; i++) {
                if (!first) out.append(' ');
                out.append(primes.get(i)).append(' ').append(primes.get(i));
                first = false;
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

